"use strict";document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelector(".burger"),t=document.querySelector(".menu"),c=document.querySelector(".overlay");function s(){t.classList.add("menu_active"),e.classList.add("burger_active"),c.classList.add("overlay_active"),document.body.style.overflow="hidden"}function a(){t.classList.remove("menu_active"),e.classList.remove("burger_active"),c.classList.remove("overlay_active"),document.body.style.overflow=""}e.addEventListener("click",()=>{t.classList.contains("menu_active")?a():s()}),t.addEventListener("click",e=>{e.target.closest("a")&&a()}),c.addEventListener("click",a)});